// Точечный поиск в Стаффе по нарушителю, руководителю и свидетелям.
// НЕ выкачиваем всю базу — только q-запросы по конкретным людям.
const helpers = this.helpers;
const token = $('Получение токена').first().json.access_token;
const src = $('When Executed by Another Workflow').first().json || {};
const subject = String(src.subject || '').trim();
const manager = String(src.manager || '').trim();
const witnessesRaw = String(src.witnesses || '').trim();

async function staff(q){
  if(!q) return [];
  try{
    const res = await helpers.httpRequest({
      method:'GET', url:'https://staff.skbkontur.ru/api/Users',
      qs:{ q, view:'large', '$top':50 },
      headers:{ Authorization:'Bearer '+token }, json:true
    });
    if(Array.isArray(res)) return res;
    if(res && Array.isArray(res.items)) return res.items;
    return [];
  }catch(e){ return []; }
}
function slim(u){
  if(!u) return null;
  return {
    id:u.id, login:u.login, email:u.email,
    fio:[u.surname,u.firstname,u.patronymic].filter(Boolean).join(' '),
    surname:u.surname, firstname:u.firstname, patronymic:u.patronymic,
    post:u.post, city:u.officeItem && u.officeItem.town,
    office:u.officeItem && u.officeItem.title, status:u.status
  };
}
function exact(list, key){
  key=String(key||'').toLowerCase();
  const kd=key.replace(/^kontur\\/,'');
  return list.find(u =>
    String(u.email||'').toLowerCase()===key ||
    String(u.login||'').toLowerCase()===key ||
    String(u.login||'').toLowerCase().replace(/^kontur\\/,'')===kd
  ) || null;
}
async function identify(term){
  if(!term) return { query:term, match:null, candidates:[] };
  const list = await staff(term);
  const ex = exact(list, term);
  if(ex) return { query:term, match:slim(ex), candidates:[] };
  return { query:term, match:null, candidates:list.slice(0,5).map(slim) };
}

const subjectResult = await identify(subject);
const managerResult = await identify(manager);

const names = witnessesRaw ? witnessesRaw.split(/[;\n]/).map(s=>s.trim()).filter(Boolean) : [];
const witnesses = [];
for(const name of names){
  const list = await staff(name);
  witnesses.push({ query:name, candidates:list.slice(0,5).map(slim) });
}

return [{ json: { subject:subjectResult, manager:managerResult, witnesses } }];
